example.query:
query {
  issues(first: 10) {
    nodes {
      id
      title
      state { name }
      assignee { name }
      priority
      createdAt
    }
    pageInfo { hasNextPage endCursor }
  }
}

mutation CreateIssue($input: IssueCreateInput!) {
  issueCreate(input: $input) {
    success
    issue { id title url }
  }
}
